// Cloudflare Worker: Third-party API Integration (SendGrid + Stripe)
// wrangler.toml should define these secrets:
// - SENDGRID_API_KEY
// - STRIPE_SECRET_KEY
// - API_AUTH_TOKEN (for authenticating requests to this worker)
// - ALLOWED_ORIGINS (comma-separated list of allowed origins)

const CORS_HEADERS = {
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

function getCorsHeaders(request, env) {
  const origin = request.headers.get('Origin') || '';
  const allowedOrigins = (env.ALLOWED_ORIGINS || '').split(',').map(o => o.trim());
  const headers = { ...CORS_HEADERS };
  if (allowedOrigins.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
  }
  return headers;
}

function jsonResponse(data, status = 200, corsHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Referrer-Policy': 'strict-origin-when-cross-origin',
      ...corsHeaders,
    },
  });
}

function errorResponse(message, status = 400, corsHeaders = {}) {
  return jsonResponse({ success: false, error: message }, status, corsHeaders);
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) {
    // Compare against self to maintain constant time
    b = a;
  }
  let result = a.length === b.length ? 0 : 1;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) {
    return false;
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return false;
  }

  const token = parts[1];
  if (!env.API_AUTH_TOKEN) {
    return false;
  }

  return timingSafeEqual(token, env.API_AUTH_TOKEN);
}

function validateEmail(email) {
  if (typeof email !== 'string') return false;
  // Basic email validation - RFC 5322 simplified
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email) && email.length <= 254;
}

function sanitizeString(str, maxLength = 1000) {
  if (typeof str !== 'string') return '';
  return str.slice(0, maxLength).replace(/[<>]/g, '');
}

// Rate limiting using Cloudflare KV (optional) or in-memory map
const rateLimitMap = new Map();

function checkRateLimit(clientIP, limit = 30, windowMs = 60000) {
  const now = Date.now();
  const key = clientIP;
  const record = rateLimitMap.get(key);

  if (!record || now - record.windowStart > windowMs) {
    rateLimitMap.set(key, { windowStart: now, count: 1 });
    return true;
  }

  if (record.count >= limit) {
    return false;
  }

  record.count++;
  return true;
}

// SendGrid Email Integration
async function sendEmail(env, { to, from, subject, textContent, htmlContent }) {
  if (!env.SENDGRID_API_KEY) {
    throw new Error('SendGrid API key not configured');
  }

  if (!validateEmail(to)) {
    throw new Error('Invalid recipient email address');
  }

  if (!validateEmail(from)) {
    throw new Error('Invalid sender email address');
  }

  if (!subject || typeof subject !== 'string') {
    throw new Error('Subject is required');
  }

  if (!textContent && !htmlContent) {
    throw new Error('Email content is required (text or HTML)');
  }

  const payload = {
    personalizations: [
      {
        to: [{ email: to }],
      },
    ],
    from: { email: from },
    subject: sanitizeString(subject, 200),
    content: [],
  };

  if (textContent) {
    payload.content.push({
      type: 'text/plain',
      value: sanitizeString(textContent, 50000),
    });
  }

  if (htmlContent) {
    payload.content.push({
      type: 'text/html',
      value: htmlContent.slice(0, 100000),
    });
  }

  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    const errorBody = await response.text();
    let errorMessage;
    try {
      const parsed = JSON.parse(errorBody);
      errorMessage = parsed.errors?.[0]?.message || 'SendGrid API error';
    } catch {
      errorMessage = 'SendGrid API error';
    }
    throw new Error(`SendGrid error (${response.status}): ${errorMessage}`);
  }

  return { success: true, messageId: response.headers.get('X-Message-Id') };
}

// Stripe Payment Integration
async function stripeRequest(env, endpoint, method = 'GET', body = null) {
  if (!env.STRIPE_SECRET_KEY) {
    throw new Error('Stripe secret key not configured');
  }

  const headers = {
    'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
    'Content-Type': 'application/x-www-form-urlencoded',
    'Stripe-Version': '2023-10-16',
  };

  const options = { method, headers };

  if (body && (method === 'POST' || method === 'PUT')) {
    const params = new URLSearchParams();
    flattenObject(body, params);
    options.body = params.toString();
  }

  const response = await fetch(`https://api.stripe.com/v1${endpoint}`, options);
  const data = await response.json();

  if (!response.ok) {
    const errorMessage = data.error?.message || 'Stripe API error';
    const errorType = data.error?.type || 'api_error';
    throw new StripeError(errorMessage, errorType, response.status);
  }

  return data;
}

function flattenObject(obj, params, prefix = '') {
  for (const [key, value] of Object.entries(obj)) {
    const fullKey = prefix ? `${prefix}[${key}]` : key;
    if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      flattenObject(value, params, fullKey);
    } else if (Array.isArray(value)) {
      value.forEach((item, index) => {
        if (typeof item === 'object') {
          flattenObject(item, params, `${fullKey}[${index}]`);
        } else {
          params.append(`${fullKey}[${index}]`, String(item));
        }
      });
    } else if (value !== undefined && value !== null) {
      params.append(fullKey, String(value));
    }
  }
}

class StripeError extends Error {
  constructor(message, type, statusCode) {
    super(message);
    this.name = 'StripeError';
    this.type = type;
    this.statusCode = statusCode;
  }
}

// Create a Stripe Payment Intent
async function createPaymentIntent(env, { amount, currency, description, metadata, receiptEmail }) {
  if (!Number.isInteger(amount) || amount < 50) {
    throw new Error('Amount must be an integer >= 50 (in smallest currency unit)');
  }

  if (amount > 99999999) {
    throw new Error('Amount exceeds maximum allowed value');
  }

  const validCurrencies = ['usd', 'eur', 'gbp', 'cad', 'aud', 'jpy'];
  const normalizedCurrency = (currency || 'usd').toLowerCase();
  if (!validCurrencies.includes(normalizedCurrency)) {
    throw new Error(`Invalid currency. Supported: ${validCurrencies.join(', ')}`);
  }

  const body = {
    amount,
    currency: normalizedCurrency,
    automatic_payment_methods: { enabled: 'true' },
  };

  if (description) {
    body.description = sanitizeString(description, 500);
  }

  if (receiptEmail && validateEmail(receiptEmail)) {
    body.receipt_email = receiptEmail;
  }

  if (metadata && typeof metadata === 'object') {
    const sanitizedMetadata = {};
    for (const [key, value] of Object.entries(metadata)) {
      const safeKey = sanitizeString(key, 40);
      const safeValue = sanitizeString(String(value), 500);
      if (safeKey) {
        sanitizedMetadata[safeKey] = safeValue;
      }
    }
    if (Object.keys(sanitizedMetadata).length > 0) {
      body.metadata = sanitizedMetadata;
    }
  }

  return await stripeRequest(env, '/payment_intents', 'POST', body);
}

// Retrieve a Stripe Payment Intent
async function getPaymentIntent(env, paymentIntentId) {
  if (!paymentIntentId || !/^pi_[a-zA-Z0-9]+$/.test(paymentIntentId)) {
    throw new Error('Invalid payment intent ID');
  }

  return await stripeRequest(env, `/payment_intents/${paymentIntentId}`);
}

// Create a Stripe Customer
async function createCustomer(env, { email, name, metadata }) {
  if (!email || !validateEmail(email)) {
    throw new Error('Valid email is required');
  }

  const body = { email };

  if (name) {
    body.name = sanitizeString(name, 200);
  }

  if (metadata && typeof metadata === 'object') {
    const sanitizedMetadata = {};
    for (const [key, value] of Object.entries(metadata)) {
      const safeKey = sanitizeString(key, 40);
      const safeValue = sanitizeString(String(value), 500);
      if (safeKey) {
        sanitizedMetadata[safeKey] = safeValue;
      }
    }
    if (Object.keys(sanitizedMetadata).length > 0) {
      body.metadata = sanitizedMetadata;
    }
  }

  return await stripeRequest(env, '/customers', 'POST', body);
}

// List Stripe Customers
async function listCustomers(env, { limit = 10, startingAfter }) {
  const safeLimit = Math.min(Math.max(1, parseInt(limit) || 10), 100);
  let endpoint = `/customers?limit=${safeLimit}`;

  if (startingAfter && /^cus_[a-zA-Z0-9]+$/.test(startingAfter)) {
    endpoint += `&starting_after=${startingAfter}`;
  }

  return await stripeRequest(env, endpoint);
}

// Create a Stripe Checkout Session
async function createCheckoutSession(env, { lineItems, successUrl, cancelUrl, customerEmail, mode }) {
  if (!lineItems || !Array.isArray(lineItems) || lineItems.length === 0) {
    throw new Error('At least one line item is required');
  }

  if (lineItems.length > 20) {
    throw new Error('Maximum 20 line items allowed');
  }

  if (!successUrl || !cancelUrl) {
    throw new Error('Success and cancel URLs are required');
  }

  // Validate URLs
  try {
    const sUrl = new URL(successUrl);
    const cUrl = new URL(cancelUrl);
    if (!['http:', 'https:'].includes(sUrl.protocol) || !['http:', 'https:'].includes(cUrl.protocol)) {
      throw new Error('Invalid URL protocol');
    }
  } catch {
    throw new Error('Invalid success or cancel URL');
  }

  const validModes = ['payment', 'subscription', 'setup'];
  const sessionMode = validModes.includes(mode) ? mode : 'payment';

  const body = {
    success_url: successUrl,
    cancel_url: cancelUrl,
    mode: sessionMode,
  };

  if (customerEmail && validateEmail(customerEmail)) {
    body.customer_email = customerEmail;
  }

  lineItems.forEach((item, index) => {
    if (!item.priceId && (!item.name || !item.amount)) {
      throw new Error(`Line item ${index} must have either priceId or name+amount`);
    }

    if (item.priceId) {
      if (!/^price_[a-zA-Z0-9]+$/.test(item.priceId)) {
        throw new Error(`Invalid price ID for line item ${index}`);
      }
      body[`line_items[${index}][price]`] = item.priceId;
      body[`line_items[${index}][quantity]`] = Math.max(1, parseInt(item.quantity) || 1);
    } else {
      body[`line_items[${index}][price_data][currency]`] = (item.currency || 'usd').toLowerCase();
      body[`line_items[${index}][price_data][product_data][name]`] = sanitizeString(item.name, 200);
      body[`line_items[${index}][price_data][unit_amount]`] = parseInt(item.amount);
      body[`line_items[${index}][quantity]`] = Math.max(1, parseInt(item.quantity) || 1);

      if (sessionMode === 'subscription') {
        body[`line_items[${index}][price_data][recurring][interval]`] = item.interval || 'month';
      }
    }
  });

  return await stripeRequest(env, '/checkout/sessions', 'POST', body);
}

// Stripe Webhook Verification
async function verifyStripeWebhook(request, env) {
  if (!env.STRIPE_WEBHOOK_SECRET) {
    throw new Error('Stripe webhook secret not configured');
  }

  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    throw new Error('Missing Stripe signature header');
  }

  const body = await request.text();

  const parts = {};
  signature.split(',').forEach(part => {
    const [key, value] = part.split('=');
    if (key && value) {
      parts[key.trim()] = value.trim();
    }
  });

  const timestamp = parts.t;
  const expectedSig = parts.v1;

  if (!timestamp || !expectedSig) {
    throw new Error('Invalid signature format');
  }

  // Check timestamp tolerance (5 minutes)
  const now = Math.floor(Date.now() / 1000);
  if (Math.abs(now - parseInt(timestamp)) > 300) {
    throw new Error('Webhook timestamp too old');
  }

  const signedPayload = `${timestamp}.${body}`;
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(env.STRIPE_WEBHOOK_SECRET),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );

  const signatureBuffer = await crypto.subtle.sign('HMAC', key, encoder.encode(signedPayload));
  const computedSig = Array.from(new Uint8Array(signatureBuffer))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');

  if (!timingSafeEqual(computedSig, expectedSig)) {
    throw new Error('Invalid webhook signature');
  }

  return JSON.parse(body);
}

// Route handlers
async function handleSendEmail(request, env, corsHeaders) {
  const body = await request.json();
  const { to, from, subject, textContent, htmlContent } = body;

  const result = await sendEmail(env, { to, from, subject, textContent, htmlContent });
  return jsonResponse({ success: true, data: result }, 200, corsHeaders);
}

async function handleCreatePaymentIntent(request, env, corsHeaders) {
  const body = await request.json();
  const { amount, currency, description, metadata, receiptEmail } = body;

  const paymentIntent = await createPaymentIntent(env, {
    amount,
    currency,
    description,
    metadata,
    receiptEmail,
  });

  return jsonResponse({
    success: true,
    data: {
      id: paymentIntent.id,
      clientSecret: paymentIntent.client_secret,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
    },
  }, 200, corsHeaders);
}

async function handleGetPaymentIntent(request, env, corsHeaders) {
  const url = new URL(request.url);
  const id = url.searchParams.get('id');

  const paymentIntent = await getPaymentIntent(env, id);

  return jsonResponse({
    success: true,
    data: {
      id: paymentIntent.id,
      amount: paymentIntent.amount,
      currency: paymentIntent.currency,
      status: paymentIntent.status,
      receiptEmail: paymentIntent.receipt_email,
    },
  }, 200, corsHeaders);
}

async function handleCreateCustomer(request, env, corsHeaders) {
  const body = await request.json();
  const { email, name, metadata } = body;

  const customer = await createCustomer(env, { email, name, metadata });

  return jsonResponse({
    success: true,
    data: {
      id: customer.id,
      email: customer.email,
      name: customer.name,
    },
  }, 200, corsHeaders);
}

async function handleListCustomers(request, env, corsHeaders) {
  const url = new URL(request.url);
  const limit = url.searchParams.get('limit');
  const startingAfter = url.searchParams.get('starting_after');

  const result = await listCustomers(env, { limit, startingAfter });

  return jsonResponse({
    success: true,
    data: {
      customers: result.data.map(c => ({
        id: c.id,
        email: c.email,
        name: c.name,
        created: c.created,
      })),
      hasMore: result.has_more,
    },
  }, 200, corsHeaders);
}

async function handleCreateCheckoutSession(request, env, corsHeaders) {
  const body = await request.json();
  const { lineItems, successUrl, cancelUrl, customerEmail, mode } = body;

  const session = await createCheckoutSession(env, {
    lineItems,
    successUrl,
    cancelUrl,
    customerEmail,
    mode,
  });

  return jsonResponse({
    success: true,
    data: {
      id: session.id,
      url: session.url,
    },
  }, 200, corsHeaders);
}

async function handleStripeWebhook(request, env, corsHeaders) {
  const event = await verifyStripeWebhook(request, env);

  // Process webhook events
  switch (event.type) {
    case 'payment_intent.succeeded': {
      const paymentIntent = event.data.object;
      console.log(`Payment succeeded: ${paymentIntent.id}`);

      // Optionally send confirmation email
      if (paymentIntent.receipt_email && env.SENDGRID_API_KEY) {
        try {
          await sendEmail(env, {
            to: paymentIntent.receipt_email,
            from: env.FROM_EMAIL || 'noreply@example.com',
            subject: 'Payment Confirmation',
            textContent: `Your payment of ${paymentIntent.amount / 100} ${paymentIntent.currency.toUpperCase()} has been received. Payment ID: ${paymentIntent.id}`,
          });
        } catch (emailError) {
          console.error('Failed to send confirmation email:', emailError.message);
        }
      }
      break;
    }

    case 'payment_intent.payment_failed': {
      const failedPayment = event.data.object;
      console.log(`Payment failed: ${failedPayment.id}`);
      break;
    }

    case 'checkout.session.completed': {
      const session = event.data.object;
      console.log(`Checkout session completed: ${session.id}`);
      break;
    }

    case 'customer.subscription.created':
    case 'customer.subscription.updated':
    case 'customer.subscription.deleted': {
      const subscription = event.data.object;
      console.log(`Subscription ${event.type}: ${subscription.id}`);
      break;
    }

    default:
      console.log(`Unhandled webhook event type: ${event.type}`);
  }

  return jsonResponse({ received: true }, 200, corsHeaders);
}

// Router
const routes = {
  'POST /api/email/send': handleSendEmail,
  'POST /api/payments/create-intent': handleCreatePaymentIntent,
  'GET /api/payments/get-intent': handleGetPaymentIntent,
  'POST /api/customers/create': handleCreateCustomer,
  'GET /api/customers/list': handleListCustomers,
  'POST /api/checkout/create-session': handleCreateCheckoutSession,
  'POST /api/webhooks/stripe': handleStripeWebhook,
};

// Endpoints that don't require auth (webhooks have their own verification)
const publicEndpoints = new Set([
  'POST /api/webhooks/stripe',
]);

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const corsHeaders = getCorsHeaders(request, env);

    // Handle CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    // Health check
    if (url.pathname === '/health' && request.method === 'GET') {
      return jsonResponse({ status: 'ok', timestamp: new Date().toISOString() }, 200, corsHeaders);
    }

    const routeKey = `${request.method} ${url.pathname}`;

    // Check if route exists
    const handler = routes[routeKey];
    if (!handler) {
      return errorResponse('Not found', 404, corsHeaders);
    }

    // Rate limiting
    const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
    if (!checkRateLimit(clientIP)) {
      return errorResponse('Rate limit exceeded. Please try again later.', 429, corsHeaders);
    }

    // Authentication (skip for public endpoints)
    if (!publicEndpoints.has(routeKey)) {
      if (!authenticateRequest(request, env)) {
        return errorResponse('Unauthorized', 401, corsHeaders);
      }
    }

    try {
      return await handler(request, env, corsHeaders);
    } catch (error) {
      console.error(`Error handling ${routeKey}:`, error.message);

      if (error instanceof StripeError) {
        const statusCode = error.statusCode >= 400 && error.statusCode < 500 ? error.statusCode : 502;
        return errorResponse(error.message, statusCode, corsHeaders);
      }

      if (error instanceof SyntaxError) {
        return errorResponse('Invalid JSON in request body', 400, corsHeaders);
      }

      // Don't leak internal error details to clients
      const isClientError = error.message && (
        error.message.includes('Invalid') ||
        error.message.includes('required') ||
        error.message.includes('must') ||
        error.message.includes('Missing')
      );

      if (isClientError) {
        return errorResponse(error.message, 400, corsHeaders);
      }

      return errorResponse('Internal server error', 500, corsHeaders);
    }
  },
};